import org.jsoup.helper.DataUtil;
import org.jsoup.helper.HttpConnection;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Safelist;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.IOException;
import java.io.InputStream;
import java.net.MalformedURLException;
import java.net.URL;

import static org.junit.jupiter.api.Assertions.*;

public class Jsoup_parse_0_Test {

    @Test
    @DisplayName("parse(html, baseUri) throws IllegalArgumentException when html is null")
    public void test_TC01() {
        String html = null;
        String baseUri = "http://example.com";
        // Check if html is null before passing it to Jsoup.parse
        if (html == null) throw new IllegalArgumentException("html cannot be null");
        // html == null → expect NPE
        assertThrows(NullPointerException.class, () -> Jsoup.parse(html, baseUri));
    }

    @Test
    @DisplayName("parse(html, baseUri) returns empty Document when html is empty string and baseUri is empty")
    public void test_TC02() {
        String html = "";
        String baseUri = "";
        // html non-null and baseUri empty → empty body
        Document doc = Jsoup.parse(html, baseUri);
        assertNotNull(doc);
        assertTrue(doc.body().children().isEmpty(), "Body should have no children");
        assertEquals("", doc.baseUri(), "Base URI should be empty");
    }

    @Test
    @DisplayName("parse(html, baseUri) correctly resolves relative URLs when baseUri non-empty")
    public void test_TC03() {
        String html = "<a href=\"page.html\">link</a>";
        String baseUri = "http://example.com/path/";
        // html non-null and baseUri non-empty → resolve relative link
        Document doc = Jsoup.parse(html, baseUri);
        Element a = doc.selectFirst("a");
        assertNotNull(a);
        assertEquals("http://example.com/path/page.html", a.attr("abs:href"),
                "abs:href should resolve against baseUri");
    }

    @Test
    @DisplayName("parse(html) delegates to parse(html,\"") and returns Document with body fragment")
    public void test_TC04() {
        String html = "<p>test</p>";
        // no-base overload uses empty baseUri
        Document doc = Jsoup.parse(html);
        assertNotNull(doc);
        assertEquals("<p>test</p>", doc.body().html());
    }

    @Test
    @DisplayName("parse(html, parser) uses custom parser to parse xml fragment")
    public void test_TC05() {
        String html = "<root><child/></root>";
        Parser parser = Parser.xmlParser();
        // xmlParser should parse <child/> as element
        Document doc = Jsoup.parse(html, parser);
        assertNotNull(doc);
        assertEquals(1, doc.select("child").size());
    }

    @Test
    @DisplayName("parse(html, baseUri, parser) uses custom parser and resolves baseUri")
    public void test_TC06() {
        String html = "<img src='img.png'>";
        String baseUri = "http://host/";
        Parser parser = Parser.xmlParser();
        // xmlParser with non-empty baseUri resolves abs:src
        Document doc = Jsoup.parse(html, baseUri, parser);
        Element img = doc.selectFirst("img");
        assertNotNull(img);
        assertEquals("http://host/img.png", img.attr("abs:src"));
    }

    @Test
    @DisplayName("parse(File, charsetName, baseUri) throws FileNotFoundException when file not found")
    public void test_TC07() throws Exception {
        File file = new File("nonexistent_12345.html");
        String charset = "UTF-8";
        String baseUri = "http://x/";
        // Check if the file exists before parsing
        if (!file.exists()) throw new FileNotFoundException("File does not exist: " + file.getPath());
        assertThrows(IOException.class, () -> Jsoup.parse(file, charset, baseUri));
    }

    @Test
    @DisplayName("parse(InputStream, charsetName, baseUri) returns Document and closes stream")
    public void test_TC08() throws IOException {
        byte[] data = "<p>hi</p>".getBytes("UTF-8");
        ByteArrayInputStream in = new ByteArrayInputStream(data);
        String charset = "UTF-8";
        String baseUri = "";
        // after parse, stream should be consumed (read pointer at end)
        Document doc = Jsoup.parse(in, charset, baseUri);
        assertNotNull(doc);
        assertEquals("<p>hi</p>", doc.body().html());
        // ByteArrayInputStream#close is no-op, but read should now be at EOF
        assertEquals(-1, in.read(), "Stream should be at EOF after parse");
    }

    @Test
    @DisplayName("parse(URL, timeoutMillis) throws MalformedURLException for ftp URL")
    public void test_TC09() throws Exception {
        URL url = new URL("ftp://example.com/resource");
        int timeout = 1000;
        // non-http(s) protocol → MalformedURLException
        assertThrows(MalformedURLException.class, () -> Jsoup.parse(url, timeout));
    }

    @Test
    @DisplayName("parse(URL, timeoutMillis) returns Document for valid URL within timeout")
    public void test_TC10() throws Exception {
        URL url = new URL("http://httpbin.org/html"); // known small HTML endpoint
        int timeout = 5000;
        // http protocol → should succeed and return a Document
        Document doc = Jsoup.parse(url, timeout);
        assertNotNull(doc);
        assertTrue(doc.body().html().length() > 0, "Document body should not be empty");
    }
}
